VALUES
  ('real-estate-moex-02312', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '以下關於最高限額抵押權之敘述何者正確？', '["最高限額抵押權所擔保之債權，包含因一定關係所生之不特定債權或基於票據所生之權利", "我國最高限額抵押權係採本金最高限額", "基於抵押權之從屬性，最高限額抵押權所擔保之任何1筆債權一旦讓與他人，最高限額抵押權亦隨之 移轉", "最高限額抵押權僅對原債權有擔保之效力"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02313', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲之配偶早(cid:760)，有乙丙丁3名子女，其中乙與A結婚，有兩子X及Y，丙丁則尚未結婚，甲有財產3000 萬元。以下敘述何者錯誤？', '["甲死(cid:760)時，其子丙已先死(cid:760)時，則甲之遺產由乙丁繼承", "甲死(cid:760)後，其子乙因悲傷過度亦於1個月後死(cid:760)，則甲之3000萬元遺產，由丙、丁各繼承1000萬元， 剩餘1000萬元由A及X、Y共同繼承", "甲死(cid:760)前，其子乙已先死(cid:760)時，則甲之3000萬元遺產，由丙、丁各繼承1000萬元，剩餘1000萬元由 A及X、Y共同繼承", "甲得以遺囑自由處分其財產，但不得侵害繼承人之特留分"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02314', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '繼承人於下列何者情形，並不喪失繼承權？', '["乙酒駕騎乘機車，不小心於家門口將其父甲撞死因而受刑之宣告", "乙為獨占全部遺產，欺騙其父甲其他兄弟丙丁與外人勾結圖謀財產，其父甲因此作成遺囑，將財產全 部遺留給乙", "乙為獨占全部遺產，私下塗改父甲之遺囑", "乙與其父甲素來相處不洽，屢次於大庭廣眾之下辱罵父甲豬狗不如，令父甲心灰意冷，向其友人A表 示遺產絕不留給乙"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02315', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲（男）乙（女）於民國94年3月結婚，甲乙依法約定分別財產制為其夫妻財產制。下列敘述，何者正確？', '["甲乙就其婚後財產，互負報告之義務", "甲乙各自保有其財產之所有權", "甲乙之債務，應由甲乙共同清償", "家庭生活費用由甲負擔，甲得請求乙為相當之負擔"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02316', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '因他人拋棄繼承而為繼承人者，其主張拋棄繼承之法定期間為何？', '["於知悉其得繼承之日起2個月內", "自繼承開始時起3個月內，必要時得向法院聲請延展", "於知悉其得繼承之日起3個月內", "自繼承開始時起2個月內，必要時得向法院聲請延展"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02317', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲（被繼承人）生前對乙（繼承人）所為之何種贈與，於計算甲之應繼遺產時，係屬應歸扣之生前特種 贈與？', '["乙結婚時，甲贈與乙100萬元", "乙生日時，甲贈與乙100萬元", "乙生子時，甲贈與乙100萬元", "乙參加競賽奪冠，甲贈與乙100萬元"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 35, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02318', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列何種行為，為違反公序良俗？', '["繼承人拋棄繼承", "夫妻約定家庭生活費用由妻負擔", "父親死(cid:760)前，兄弟姊妹預先訂約剝奪母親之應繼分", "出租人與承租人約定，承租人應負責修繕租賃標的物"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 36, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02319', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於收養子女，下列敘述，何者錯誤？', '["收養子女應輩分相當", "被收養人已結婚者，其出養之意思，自己決定，不必得配偶之同意", "除夫妻共同收養外，1人不能同時為2人之養子女", "收養子女，除訂立收養契約外，應經法院之認可"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 37, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02320', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於夫妻財產制之敘述何者錯誤？', '["除法定財產制外，夫妻可以約定為共同財產制或分別財產制", "夫妻約定財產制時，應以書面為之", "夫妻約定財產制不須登記可以對抗第三人", "共同財產制之下，除夫妻特有財產以外之財產合併為共同財產，屬夫妻公同共有"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 38, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-02321', 'real-estate', 'real-estate-moex-099-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲死(cid:760)留有總計5000萬元之現金存款，但同時積欠銀行7000萬元債務未清償，其妻早已死(cid:760)，子女有 乙丙丁戊4人。以下敘述何者正確？', '["在一般情形，因為遺產不足清償債務，不足之2000萬元應由乙丙丁戊4人平均分攤", "乙如欲拋棄繼承，應於知悉繼承之時起2個月內，以書面向法院為之", "乙拋棄繼承時，其應繼承之遺產歸國家所有", "分割遺產之前，各繼承人對遺產全部為公同共有"]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:10:12+00:00", "source_pdf_sha1": "d6cba8e1beb5", "answer_pdf_sha1": "560f32781bc5", "source_family": "moex-gov-tw", "moex": {"exam_code": "099220", "c": "601", "s": "200", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "民法概要", "year": "099", "exam_name": "099年建築師、技師、不動產經紀人、記帳士考試", "original_question_number": 39, "answer_corrected": false, "flags": ["answer_missing"], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
